defmodule MyAppWeb.ProxyController do
  use MyAppWeb, :controller
  alias MyAppWeb.Router.Helpers, as: Routes

  @allowlist ["example.com", "another-allowed-domain.com"]
  @private_ip_ranges [
    {~r/^10\./, 8},
    {~r/^172\.(1[6-9]|2[0-9]|3[0-1])\./, 12},
    {~r/^192\.168\./, 16}
  ]

  def fetch_content(conn, %{"url" => url}) do
    with :ok <- validate_url(url),
         :ok <- check_allowlist(url),
         :ok <- check_private_ip(url),
         {:ok, response} <- HTTPoison.get(url, [], follow_redirect: false) do
      send_resp(conn, response.status_code, response.body)
    else
      {:error, reason} -> send_resp(conn, 400, reason)
      {:error, %HTTPoison.Error{reason: reason}} -> send_resp(conn, 500, "HTTPoison error: #{reason}")
    end
  end

  defp validate_url(url) do
    case URI.parse(url) do
      %URI{scheme: "http" | "https", host: host} when not is_nil(host) -> :ok
      _ -> {:error, "Invalid URL"}
    end
  end

  defp check_allowlist(url) do
    host = URI.parse(url).host
    if Enum.any?(@allowlist, &String.ends_with?(host, &1)), do: :ok, else: {:error, "Host not allowlisted"}
  end

  defp check_private_ip(url) do
    host = URI.parse(url).host
    case :inet.gethostbyname(to_charlist(host)) do
      {:ok, {:hostent, _, _, :inet, _, [ip | _]}} ->
        if Enum.any?(@private_ip_ranges, fn {regex, _} -> Regex.match?(regex, Tuple.to_list(ip) |> Enum.join(".")) end),
          do: {:error, "Private IP range not allowed"},
          else: :ok
      _ -> {:error, "Unable to resolve host"}
    end
  end
